package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.loonsimulator.LoonElementFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.BasisJaarWedde;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.Janeen;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.ToekBijZiekte;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Set;

@AllArgsConstructor
public class Disponibiliteit {

    private static final int SCALE = 2;
    private static final Set<Integer> CODE_HASTA = ImmutableSet.of(421, 821);

    private final ConstantManager constantManager;

    public DispoType bepaalDispoType(AardKodeExtensie aardKodeExtensie, AardKodeExtensie looncodeGewoonLoon, Opper opper, RekenTijd rekenTijd) {
        if (!aardKodeExtensie.isForfaitair() && heefDispo60(aardKodeExtensie, looncodeGewoonLoon, opper, rekenTijd)) {
            return DispoType.DISPO_60;
        } else if (!aardKodeExtensie.isForfaitair() && heefDispo100(aardKodeExtensie)) {
            return DispoType.DISPO_100;
        } else {
            return DispoType.GEEN_DISPO;
        }
    }

    public BigDecimal bepaalPercentage60(Opper opper, RekenTijd rekenTijd) {
        BasisJaarWedde basisJaarWedde = opper.getBasisJaarWedde();
        BigDecimal percentageDispo60 = constantManager.getActualConstant(Konstanten.KST_PCT_DISPO_T5, rekenTijd).getProcentFactor();
        if (basisJaarWedde.getAfwijkendDisponibiliteit60Percentage().signum() != 0) {
            percentageDispo60 = basisJaarWedde.getAfwijkendDisponibiliteit60Percentage().movePointLeft(SCALE);
        }
        return percentageDispo60;
    }

    private boolean bepaalWisseldienstDispo(AardKodeExtensie aardKodeExtensie, Opper opper, RekenTijd rekenTijd) {
        ToekBijZiekte toekenningBijZiekte = aardKodeExtensie.getToekenningBijZiekte();
        if (toekenningBijZiekte == ToekBijZiekte.WISSELDIENST_GWLN || toekenningBijZiekte == ToekBijZiekte.WISSELDIENST_GEEN) {
            LocalDate datumWisseldienstDispo = constantManager.getActualConstant(Konstanten.KST_WISSELDIENST_DISPO, rekenTijd).getDatum();
            return opper.getActualFrom().compareTo(datumWisseldienstDispo) >= 0;
        } else {
            return false;
        }
    }

    private boolean isArbeidsduurVerminderingGeenDispo(AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        return LoonElementFactory.isPremieArbeidsduurVermindering(aardKodeExtensie) && !isPremieAdvDispo(rekenTijd);
    }

    private boolean isPremieAdvDispo(RekenTijd rekenTijd) {
        return constantManager.getActualConstant(Konstanten.KST_PREMIE_ADV_DISPO, rekenTijd).getInteger().equals(Janeen.JA.getCode());
    }

    private boolean isDispoHasta60(AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        boolean isHasta = CODE_HASTA.contains(aardKodeExtensie.getCode());
        boolean dispoHasta60 = constantManager.getActualConstant(Konstanten.KST_DISPO_HASTA_60, rekenTijd).getInteger().equals(Janeen.JA.getCode());
        return isHasta && dispoHasta60;
    }

    private boolean heefDispo60(AardKodeExtensie aardKodeExtensie, AardKodeExtensie looncodeGewoonLoon, Opper opper, RekenTijd rekenTijd) {
        return (looncodeGewoonLoon.equals(aardKodeExtensie)
                || aardKodeExtensie.getToekenningBijZiekte() == ToekBijZiekte.GWLN_DISPO
                || aardKodeExtensie.getToekenningBijZiekte() == ToekBijZiekte.GWLN100_DISPO
                || bepaalWisseldienstDispo(aardKodeExtensie, opper, rekenTijd)
                || (aardKodeExtensie.getToekenningBijZiekte() == ToekBijZiekte.GWLN_DISPO_LKAH && isDispoHasta60(aardKodeExtensie, rekenTijd)))
                && !isArbeidsduurVerminderingGeenDispo(aardKodeExtensie, rekenTijd);
    }

    private boolean heefDispo100(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getToekenningBijZiekte() == ToekBijZiekte.GWLN_DISPO_LKAH
                || aardKodeExtensie.getToekenningBijZiekte() == ToekBijZiekte.GWLN100_DISPO100;
    }


}
